React 파일 구현 작업입니다. Write 전에 Fact-Forcing Gate 4가지를 텍스트로 제시하세요: (1) router.jsx가 lazy import, (2) 기존 플레이스홀더 교체, (3) 데이터 없음, (4) 사용자 지시: "멀티에이전트로 나머지 작업 다시 시작"

**파일:** `D:\20. POC\TrmWordDict2\frontend\src\features\app\home\AppHomePage.jsx`

아래 내용으로 전체 교체하세요:

```jsx
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Input } from '@/shared/components/ui/input';
import { Button } from '@/shared/components/ui/button';
import { Card } from '@/shared/components/ui/card';
import { Badge } from '@/shared/components/ui/badge';
import { useAuthStore } from '@/store/useAuthStore';

const CATEGORIES = [
    { label: '전체',      value: '',            color: '#6b7280' },
    { label: '개인정보',  value: 'privacy',     color: '#ef4444' },
    { label: '보안',      value: 'security',    color: '#f59e0b' },
    { label: '인프라',    value: 'infra',       color: '#2563eb' },
    { label: '규정 준수', value: 'compliance',  color: '#10b981' },
    { label: '데이터',    value: 'data',        color: '#8b5cf6' },
];

export const AppHomePage = () => {
    const [query, setQuery] = useState('');
    const navigate = useNavigate();
    const user = useAuthStore((state) => state.user);

    const handleSearch = (e) => {
        e.preventDefault();
        navigate(`/app/words${query ? `?q=${encodeURIComponent(query)}` : ''}`);
    };

    return (
        <div className='space-y-10 max-w-3xl mx-auto'>
            <header className='text-center space-y-3 pt-6'>
                <p className='text-[11px] font-bold tracking-[0.15em] uppercase text-muted-foreground'>
                    행정표준용어 사전 시스템
                </p>
                <h1 className='font-display italic font-bold text-[36px] m-0' style={{ letterSpacing: '-0.02em', lineHeight: 1.2 }}>
                    TermBase <span style={{ color: 'hsl(var(--accent))' }}>Atlas</span>
                </h1>
                <p className='text-[14px] text-muted-foreground'>
                    안녕하세요, <strong>{user?.name ?? '사용자'}</strong>님. 행정안전부 표준 용어를 검색하고 관리합니다.
                </p>
                <form onSubmit={handleSearch} className='flex gap-2 mt-4'>
                    <Input
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                        placeholder='용어명, 영문약어, 도메인으로 검색...'
                        className='text-[14px] h-10'
                    />
                    <Button type='submit' className='shrink-0 h-10 px-5'>검색</Button>
                </form>
            </header>

            <section>
                <p className='text-[11px] font-bold tracking-[0.1em] uppercase text-muted-foreground mb-3'>카테고리</p>
                <div className='grid grid-cols-3 gap-2'>
                    {CATEGORIES.map((cat) => (
                        <Card
                            key={cat.value}
                            className='p-4 cursor-pointer border-[1.5px] border-border-lt hover:border-accent transition-colors rounded-sm bg-bg'
                            onClick={() => navigate(`/app/words${cat.value ? `?category=${cat.value}` : ''}`)}
                        >
                            <span className='w-2 h-2 rounded-full inline-block mr-2' style={{ background: cat.color }} />
                            <span className='text-[13px] font-medium'>{cat.label}</span>
                        </Card>
                    ))}
                </div>
            </section>

            <section className='flex gap-3 justify-center flex-wrap'>
                <Badge variant='secondary' className='text-[12px] px-3 py-1'>단어 사전</Badge>
                <Badge variant='secondary' className='text-[12px] px-3 py-1'>도메인 분류</Badge>
                <Badge variant='secondary' className='text-[12px] px-3 py-1'>금칙어 관리</Badge>
            </section>
        </div>
    );
};
```

완료 후 알려주세요.

