47	        ],
48	    },
49	    {
50	        element: <ProtectedRoute><AdminRoute><AdminLayout /></AdminRoute></ProtectedRoute>,
51	        children: [
52	            { path: '/admin/dashboard', element: ws(<DashboardPage />) },
53	            { path: '/admin/data',      element: ws(<DataManagePage />) },
54	            { path: '/admin/mcp',       element: ws(<McpPage />) },
55	            { path: '/admin/stats',     element: ws(<StatsPage />) },
56	            { path: '/admin/settings',  element: ws(<SettingsPage />) },
57	            { path: '/admin/words',     element: ws(<AdminWordPage />) },
58	            { path: '/admin/domains',   element: ws(<AdminDomainPage />) },
59	            { path: '/admin/forbidden', element: ws(<AdminForbiddenPage />) },
60	        ],
61	    },
62	    { path: '/',  element: <Navigate to='/app/home' replace /> },
